#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        int mark;
        for (int i = 0; i < 3; ++i) {
            scanf("%d", &mark);
            if (mark > 90) printf("A\n");
            else if (mark > 70) printf("B\n");
            else if (mark >= 40) printf("C\n");
            else printf("F\n");
        }
    }
    return 0;
}

