import sys

def grade(m):
    if m > 90:
        return 'A'
    elif m > 70:
        return 'B'
    elif m >= 40:
        return 'C'
    else:
        return 'F'

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
out = []
for _ in range(T):
    for _ in range(3):
        mark = int(data[idx]); idx += 1
        out.append(grade(mark))
print('\n'.join(out))

